     * @param {string} currentS
     * @returns {boolean} True if it contains the forbidden subsequences, false otherwise.
     */
    function containsForbiddenSubsequence(currentS) {
        // Check for "011"
        let count0 = 0;
        let count1 = 0;
        for (const char of currentS) {
            if (char === '0') {
                count0++;
            } else { // char === '1'
                count1++;
            }
            // Check if we have at least one '0' and two '1's in sequence
            if (count0 >= 1 && count1 >= 2) {
                // This simple counting approach is flawed for subsequence checking.
                // We need to track indices or use dynamic programming/state machine.

                // A correct way to check for a specific subsequence like "011":
                let found0 = false;
                let found1_1 = false;
                for (let i = 0; i < currentS.length; i++) {
                    if (currentS[i] === '0') {
