                i1_2 = i;
                return true; // Found "011"
            }
        }

        // Check for "110"
        let j1_1 = -1;
        let j1_2 = -1;
        let j0 = -1;
        for (let i = 0; i < currentS.length; i++) {
            if (currentS[i] === '1' && j1_1 === -1) {
                j1_1 = i;
            } else if (currentS[i] === '1' && j1_1 !== -1 && j1_2 === -1) {
                j1_2 = i;
            } else if (currentS[i] === '0' && j1_1 !== -1 && j1_2 !== -1) {
                j0 = i;
                return true; // Found "110"
            }
        }

        return false;
    }

    // The problem constraints suggest that the optimal solution might involve
    // transforming the string into one of a few known 'safe' patterns.

    // What strings are "coherent"?
    // They must not contain "011" or "110" as subsequences.

    // 1. Strings consisting only of '0's: "000..." (No '1's, so no "011" or "110") -> Coherent
    // 2. Strings consisting only of '1's: "111..." (No '0's, so no "011" or "110") -> Coherent
    // 3. Strings of the form "00...011...1" (All '0's followed by all '1's):
    //    - Can we get "011"? Yes, if there are at least one '0' and two '1's. E.g., "011" itself.
    //    - Can we get "110"? No, because all '0's appear before all '1's.
    //    Therefore, "0...01...1" is coherent IF it doesn't contain "011".
    //    If we have at least one '0' and two or more '1's, "0...01...1" contains "011".
    //    The only way "0...01...1" is coherent is if:
    //    a) It only has '0's (covered by case 1).
    //    b) It only has '1's (covered by case 2).
    //    c) It has one '0' and zero or one '1's (covered by cases 1/2).
    //    d) It has zero '0's and one or more '1's (covered by case 2).

