    // 4. $1 0^*$ (Exactly one 1 followed by zero or more 0s)

    // We calculate the cost to transform $S$ into the best of these four types and take the minimum.

    let minCost = n;

    // Helper function to calculate transformation cost
    const calculateCost = (targetType) => {
