object Solution {
  /**
   * Checks if the string s contains "011" or "110" as a subsequence.
   * This function is complex to implement correctly and is generally avoided
   * if a structural property can be determined.
   * However, based on problem analysis, the minimal cost is achieved by
   * transforming the string into one of four simple, known coherent structures:
   * 1. All '0's (0*)
   * 2. All '1's (1*)
   * 3. 0*1 (Zero or more 0s followed by exactly one 1)
   * 4. 10* (Exactly one 1 followed by zero or more 0s)
   */
  def s(s: String): Long = {
    val n = s.length.toInt
    if (n == 0) return 0L

    var minCost: Long = n.toLong

    // Helper to calculate the minimum cost to match a target structure
    def calculateCost(targetStructure: String): Long = {
      var cost: Long = 0
      for (i <- 0 until n) {
        val char = s(i)
        targetStructure match {
          case "ALL_0" =>
            if (char == '1') cost += 1
          case "ALL_1" =>
            if (char == '0') cost += 1
          case "0*1" =>
            // Target: 0...01 (n-1 '0's, 1 '1')
            if (i < n - 1) { // Positions 0 to n-2 should be '0'
              if (char == '1') cost += 1 // Should be '0'
            } else { // Position n-1 must be '1'
              if (char == '0') cost += 1 // Should be '1'
            }
          case "10*" =>
            // Target: 10...0 (1 '1', n-1 '0's)
            if (i == 0) { // Position 0 must be '1'
              if (char == '0') cost += 1 // Should be '1'
            } else { // Positions 1 to n-1 should be '0'
              if (char == '1') cost += 1 // Should be '0'
            }
          case _ => 0L // Should not happen
        }
      }
      cost
    }

    // 1. Target: All '0's
    val costAll0 = calculateCost("ALL_0")
    minCost = Math.min(minCost, costAll0)

    // 2. Target: All '1's
    val costAll1 = calculateCost("ALL_1")
    minCost = Math.min(minCost, costAll1)

    // 3. Target: 0*1 (n-1 zeros followed by one 1)
    val cost0Star1 = calculateCost("0*1")
    minCost = Math.min(minCost, cost0Star1)

    // 4. Target: 10* (One 1 followed by n-1 zeros)
    val cost10Star = calculateCost("10*")
    minCost = Math.min(minCost, cost10Star)

    minCost
  }
}
