object Solution {
  /**
    * Given a binary string s, returns the minimum number of flips required to make s coherent.
    * A string is coherent if it does not contain "011" or "110" as a subsequence.
    *
    * The coherent strings must be one of the following forms:
    * 1. All '0's (0*0)
    * 2. All '1's (1*1)
    * 3. Zero or more '0's followed by exactly one '1' (0*1)
    * 4. Exactly one '1' followed by zero or more '0's (10*)
    *
    * @param s The input binary string.
    * @return The minimum number of modifications.
    */
  def s(s: String): Long = {
    val n = s.length
    if (n == 0) return 0L

    var minCost: Long = Long.MaxValue

    // Helper to calculate cost to match a target pattern
    def calculateCost(targetPattern: String): Long = {
      var cost: Long = 0
      for (i <- 0 until n) {
        val char = s.charAt(i)
        val targetChar = targetPattern.charAt(i)
        if (char != targetChar) {
          cost += 1
        }
      }
      cost
    }

    // 1. Target: All '0's (0*0)
    val targetAll0 = "0".repeat(n)
    minCost = Math.min(minCost, calculateCost(targetAll0))

    // 2. Target: All '1's (1*1)
    val targetAll1 = "1".repeat(n)
    minCost = Math.min(minCost, calculateCost(targetAll1))

    // 3. Target: 0*1 (n-1 zeros followed by one 1)
    // This requires n >= 1.
    if (n >= 1) {
      val target0Star1 = "0".repeat(n - 1) + "1"
      minCost = Math.min(minCost, calculateCost(target0Star1))
    }

    // 4. Target: 10* (One 1 followed by n-1 zeros)
    // This requires n >= 1.
    if (n >= 1) {
      val target10Star = "1" + "0".repeat(n - 1)
      minCost = Math.min(minCost, calculateCost(target10Star))
    }

    minCost
  }
}
